repl("Collecting hotel detail links from Skyscanner", "const hotelTargets = [
  [9, ['NH Malaga','Posadas de España Malaga']],
  [10, ['Quinta Da Penha De Franca','Meliá Madeira Mare']],
  [11, ['La Maison Arabe Hotel','Hotel Amalay']],
  [12, ['Résidence Hotelière Fleurie','Allegro Agadir']]
];
const hotelLinks1 = [];
for (const [idx,names] of hotelTargets) {
  page = tabs[idx];
  for (const nm of names) {
    const loc = page.getByRole('link', {name: new RegExp(nm.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'i')}).first();
    const href = await loc.getAttribute('href');
    hotelLinks1.push({idx,nm,href});
    console.log(idx+' '+nm+' => '+href);
  }
}
console.log(JSON.stringify(hotelLinks1));")

